#!/usr/bin/env python3
"""
patch_v367_multi_tf_shadow.py  (v19.34.367 — P1-MULTI-TF multi-bar-size shadow logging).

Anchored-chunk patcher (DGX §2.2 convention). Rewrites ConfidenceGate._get_live_prediction
in backend/services/ai_modules/confidence_gate.py so the P-WIRE regime-shadow is computed
across 1min/5min/15min (additive list result["regime_shadows"]) instead of only 5min. The
PRIMARY live prediction path is BYTE-FOR-BYTE UNCHANGED (drives confidence/execution); the
single result["regime_shadow"] (5min/daily) is preserved for backward-compatible readers.
Read-only shadow — never affects execution. Reversible via env PWIRE_MULTI_TF_SHADOW=0.

Guards: whole-file PRE-SHA + POST-SHA, OLD anchor count==1, post-replace self-check + py_compile,
auto-backup (*.v367.bak). Supports --check (dry-run).

Usage (DGX, repo root):
  .venv/bin/python /tmp/patch_v367_multi_tf_shadow.py --check
  .venv/bin/python /tmp/patch_v367_multi_tf_shadow.py
"""
import base64, hashlib, sys, py_compile, tempfile, os, shutil

FILE = "backend/services/ai_modules/confidence_gate.py"
PRE_FILE_SHA  = "454318302b85bfd17f6e2b789221c074bfa08b30d30c4b8f28828ed9cb35193a"
POST_FILE_SHA = "f8e4a542a8c17c9ad5fbcf39220628dec90c2466f468fc08bdce109cec2f8c5b"
OLD_B64 = ""
NEW_B64 = ""

def main():
    check = "--check" in sys.argv
    if not os.path.exists(FILE):
        print(f"ABORT: {FILE} not found (run from repo root)"); sys.exit(2)
    src = open(FILE, encoding="utf-8").read()
    cur = hashlib.sha256(src.encode()).hexdigest()
    if cur == POST_FILE_SHA:
        print("Already at POST SHA — patch already applied. Nothing to do."); sys.exit(0)
    if cur != PRE_FILE_SHA:
        print("ABORT: whole-file SHA drift.")
        print(f"  expected PRE : {PRE_FILE_SHA}")
        print(f"  actual       : {cur}")
        print("  -> DGX file differs from the build baseline. Re-extract and rebase the patch.")
        sys.exit(3)
    OLD = base64.b64decode(OLD_B64).decode("utf-8")
    NEW = base64.b64decode(NEW_B64).decode("utf-8")
    n = src.count(OLD)
    if n != 1:
        print(f"ABORT: OLD anchor count = {n} (must be 1)"); sys.exit(4)
    patched = src.replace(OLD, NEW, 1)
    post = hashlib.sha256(patched.encode()).hexdigest()
    if post != POST_FILE_SHA:
        print(f"ABORT: post-replace SHA {post} != expected {POST_FILE_SHA}"); sys.exit(5)
    # compile-check the patched content before writing
    with tempfile.NamedTemporaryFile("w", suffix=".py", delete=False) as tf:
        tf.write(patched); tmp = tf.name
    try:
        py_compile.compile(tmp, doraise=True)
    finally:
        os.unlink(tmp)
    if check:
        print("CHECK OK — PRE/POST SHA + anchor + py_compile all pass. (no write)")
        sys.exit(0)
    shutil.copy2(FILE, FILE + ".v367.bak")
    open(FILE, "w", encoding="utf-8").write(patched)
    print(f"APPLIED v367. backup: {FILE}.v367.bak")
    print(f"  new whole-file SHA: {hashlib.sha256(patched.encode()).hexdigest()}")

if __name__ == "__main__":
    main()
